const express = require('express');
const redis = require('redis');
const app = express();
const port = 3000;

// Create a Redis client
const client = redis.createClient();

client.on('error', (err) => {
  console.error('Redis error:', err);
});

app.use(express.json());

// Securely handle search patterns with KEYS command
app.get('/search', (req, res) => {
  const pattern = req.query.pattern;
  
  if (!pattern || !/^[a-zA-Z0-9_]+$/.test(pattern)) {
    return res.status(400).send('Invalid pattern');
  }

  client.keys(pattern, (err, keys) => {
    if (err) {
      return res.status(500).send('Redis error');
    }
    res.json(keys);
  });
});

// Securely execute Redis commands based on user input
app.post('/execute', (req, res) => {
  const command = req.body.command;
  const args = req.body.args || [];

  if (!command || !/^[a-zA-Z0-9_]+$/.test(command)) {
    return res.status(400).send('Invalid command');
  }

  client.sendCommand([command, ...args], (err, result) => {
    if (err) {
      return res.status(500).send('Redis error');
    }
    res.json(result);
  });
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});